var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":"오오, 보면 볼수록 경이로운 광경이야……","JPN":"おお、見れば見るほど脅威的な光景だ……","ENG":"Wow... The more I look at it, the more wondrous it is...","TWN":"喔，真是越看越神奇……"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":"학회장님께서 손톱만큼 작은 파편이라도 하사해 주시지 않을까?","JPN":"学会長がほんの小さな破片でもいいから与えてくださらないだろうか？","ENG":"I wonder if the President will gift us a very small Fragment of knowledge to us.","TWN":"學會長應該會賞賜給我們指甲那麼大的碎片吧？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":"감상에 빠져 있지 말고 손이나 움직여.","JPN":"感激してないで、手を動かせ。","ENG":"Stop daydreaming and work.","TWN":"別欣賞了，動手吧。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":"사진이든 스케치든 기록으로 남길 수 있는 건 뭐든 하라고.","JPN":"写真でもスケッチでも、記録として残せるものは何でも残せ。","ENG":"Create whatever record you can, whether it's a picture or a sketch.","TWN":"不管是照片還是素描，能留作記錄的都要留下。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":"뭐야, 왜 대답이……","JPN":"おい、なんで返事を……","ENG":"Huh? Why aren't you ans–","TWN":"幹嘛，怎麼不回答……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"안녕하신가, 친구.","JPN":"ちょっと失礼するぞ。","ENG":"Hello there.","TWN":"你們好啊，朋友。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"경계가 허술하군요. 다들 넋을 놓고 저 흉물만 구경하기 바쁜 듯합니다.","JPN":"警戒が緩いですね。みなさん、あの気持ち悪いものに目を奪われていて気付かないようです。","ENG":"Do you think their security is lacking? They're all gawking at that monstrosity.","TWN":"警戒很鬆懈啊。大家好像都在忙著看那個怪物呢。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그야 어쩔 수 없지. 학회원들에게는 저 파편이 보물 더미 같을 테니까.","JPN":"それは仕方ない。学会員にとっては、あの破片が宝の山に見えるだろうからな。","ENG":"But what can you do? To the Society members, those Fragment must look like gold.","TWN":"這也是沒辦法的事。因為對於學會成員來說，那個碎片就像一堆寶物。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"게다가 보게나. 허술해 보여도 준비성이 좋은 친구들이야.","JPN":"それに、見ろ。緩く見えても手回しのいいやつらだ。","ENG":"And just look. Although it might seem sloppy, they are well organized.","TWN":"再說了，你看看，他們雖然看起來很鬆懈，但是都有所準備。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"교활한 장수여. 분명 조용히 들어가겠다고 하지 않았던가.","JPN":"狡猾な将軍よ。確か、目立たぬよう侵入すると言っていなかったか？","ENG":"Ye cunning knight. Didn't you say we would go in quietly?","TWN":"狡猾的商人，我分明說過要安靜地進去的。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"작전 목표에 대해 말해 주지 않았나?","JPN":"作戦目標について話しただろう？","ENG":"Didn't I tell you about the operation goal?","TWN":"我沒說過作戰目標嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"집중을 흐트러뜨리는 데에는 앞마당에서 설치는 게 제일이지.","JPN":"集中を乱すには、庭で暴れるのが一番だ。","ENG":"Distracting them in front of them is the most effective method.","TWN":"為了分散注意力，最好在前院安裝。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어때, 아가씨도 그렇게 생각하나?","JPN":"どうだ、お嬢さんもそう思わないか？","ENG":"Don't you feel the same way, Miss?","TWN":"怎麼樣，小姐也是這麼想的嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄. 재빠르게 숨어든 것만은 칭찬해 줄게.","JPN":"どうかしら。素早く忍び込んだのは褒めてあげるわ。","ENG":"Maybe. But I will compliment you on your swift invasion.","TWN":"這個嘛，我只想誇一句，躲得挺快。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 낡아빠진 인간이랑 빈털터리 예하에…… 호라이즌인가.","JPN":"でも、古くさい人間に貧乏猊下に……ホライズンね。","ENG":"But aren't they just one old-fashioned human, a penniless Eminence, and... Horizon?","TWN":"不過殘破的人類和虛有其表的主教……是地平線嗎。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그로니아에 비해서도 너무 단촐하지 않아?","JPN":"グロニアに比べても少なすぎると思わない？","ENG":"Doesn't that seem too small compared to in Gronia?","TWN":"與格羅尼亞相比，是不是太過簡單了？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};